@app.route('/book_ticket', methods=['GET', 'POST'])
def ticket_booking():
    if request.method == 'GET':
        events = load_events()
        return render_template('ticket_booking.html', events=events)

    # For POST: process booking
    events = load_events()
    tickets = load_tickets()
    bookings = load_bookings()

    form = request.form
    try:
        event_id = int(form.get('event_id', ''))
        ticket_type = form.get('ticket_type', '').strip()
        ticket_count = int(form.get('ticket_count', ''))
        customer_name = form.get('customer_name', '').strip()
    except Exception:
        error_message = "Invalid form data submitted."
        return render_template('ticket_booking.html', error_message=error_message)

    # Validate event exists
    event = next((e for e in events if e['event_id'] == event_id), None)
    if event is None:
        error_message = "Selected event does not exist."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    # Validate ticket type exists for event and availability
    ticket = next((t for t in tickets if t['event_id'] == event_id and t['ticket_type'] == ticket_type), None)
    if ticket is None:
        error_message = "Selected ticket type not available for this event."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    if ticket_count <= 0:
        error_message = "Ticket count must be a positive integer."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    if ticket['available_count'] < ticket_count:
        error_message = f"Only {ticket['available_count']} tickets available for selected ticket type."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    # Create new booking_id
    new_booking_id = 1
    if bookings:
        new_booking_id = max(b['booking_id'] for b in bookings) + 1

    booking_date = datetime.now().strftime('%Y-%m-%d')
    total_amount = ticket_count * ticket['price']

    new_booking = {
        'booking_id': new_booking_id,
        'event_id': event_id,
        'customer_name': customer_name,
        'booking_date': booking_date,
        'ticket_count': ticket_count,
        'ticket_type': ticket_type,
        'total_amount': total_amount,
        'status': 'Confirmed'
    }

    # Update ticket availability: decrement available_count and increase sold_count
    ticket['available_count'] -= ticket_count
    ticket['sold_count'] += ticket_count

    # Persist updated tickets and bookings to files
    # Updating tickets.txt
    try:
        all_tickets = load_tickets()  # reload original with no modification
        # Update the matched ticket in all_tickets
        for t in all_tickets:
            if t['ticket_id'] == ticket['ticket_id']:
                t['available_count'] = ticket['available_count']
                t['sold_count'] = ticket['sold_count']
                break
        # Write back tickets
        path_tickets = os.path.join(DATA_DIR, 'tickets.txt')
        with open(path_tickets, 'w', encoding='utf-8') as f:
            for t in all_tickets:
                line = f"{t['ticket_id']}|{t['event_id']}|{t['ticket_type']}|{t['price']}|{t['available_count']}|{t['sold_count']}\n"
                f.write(line)
    except Exception:
        error_message = "Failed to update ticket availability."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    # Append new booking
    try:
        path_bookings = os.path.join(DATA_DIR, 'bookings.txt')
        with open(path_bookings, 'a', encoding='utf-8') as f:
            line = f"{new_booking['booking_id']}|{new_booking['event_id']}|{new_booking['customer_name']}|{new_booking['booking_date']}|{new_booking['ticket_count']}|{new_booking['ticket_type']}|{new_booking['total_amount']}|{new_booking['status']}\n"
            f.write(line)
    except Exception:
        error_message = "Failed to save booking."
        return render_template('ticket_booking.html', error_message=error_message, events=events)

    return render_template('ticket_booking.html', booking_confirmation=new_booking)


