@app.route('/bookings')
def bookings_summary():
    all_bookings = load_bookings()

    # Optionally handle cancellation action from query params
    cancel_booking_id = request.args.get('cancel_booking_id', '')
    if cancel_booking_id.isdigit():
        cancel_id = int(cancel_booking_id)
        # Load bookings and remove the booking with given id if possible, mark status as 'Cancelled'
        updated = False
        for b in all_bookings:
            if b['booking_id'] == cancel_id and b['status'] != 'Cancelled':
                b['status'] = 'Cancelled'
                updated = True
                break
        if updated:
            # Save back bookings
            try:
                path_bookings = os.path.join(DATA_DIR, 'bookings.txt')
                with open(path_bookings, 'w', encoding='utf-8') as f:
                    for b in all_bookings:
                        line = f"{b['booking_id']}|{b['event_id']}|{b['customer_name']}|{b['booking_date']}|{b['ticket_count']}|{b['ticket_type']}|{b['total_amount']}|{b['status']}\n"
                        f.write(line)
            except Exception:
                # On failure, ignore and continue without update
                pass

    return render_template('bookings.html', bookings=all_bookings)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

